import React from 'react';
import '../Styles/Contact.css';

function Contact() {
  return (
    <section id="contact" className="contact">
      <h2>Contact Me</h2>
      <p>Let’s build something amazing together!</p>
      <p>Email: <a href="mailto:vishal@example.com">vishalshanmugam928@example.com</a></p>
      <p>LinkedIn: <a href="https://www.linkedin.com/in/vishal-vishal-3711ba293/" target="_blank" rel="noreferrer">linkedin.com/in/vishal</a></p>
      <p>GitHub: <a href="https://github.com/vishal-viji" target="_blank" rel="noreferrer">github.com/vishal</a></p>
    </section>
  );
}

export default Contact;
